#include<bits/stdc++.h>
#define l long long
using namespace std;
const int MAXN=5e4+1;
l n,a[MAXN],b[MAXN],ans=0;
int main(void){
	ios::sync_with_stdio(false);
	cin>>n;
	for(l i=1;i<=n;i++)cin>>a[i];
	for(l i=1;i<=n;i++)cin>>b[i];
	sort(a+1,a+1+n);
	sort(b+1,b+1+n);
	for(l i=1,j=1;i<=n;i++){
		if(a[i]>=b[j])j+=1,ans++;
	}
	cout<<ans;
	return false;
}
